import{_ as t,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"인증 실패: 401 오류 문제 해결 | Antigravity-Manager","description":"Antigravity Tools 프록시의 인증 메커니즘을 학습하고 401 오류를 문제 해결합니다. auth_mode, api_key, Header 순서로 문제를 찾아내고, auto 모드 규칙과 /healthz 제외, Header 우선순위 오해를 피하는 방법을 이해하세요.","frontmatter":{"title":"인증 실패: 401 오류 문제 해결 | Antigravity-Manager","sidebarTitle":"3분 만에 401 해결","subtitle":"401/인증 실패: 먼저 auth_mode 확인, 다음 Header 확인","description":"Antigravity Tools 프록시의 인증 메커니즘을 학습하고 401 오류를 문제 해결합니다. auth_mode, api_key, Header 순서로 문제를 찾아내고, auto 모드 규칙과 /healthz 제외, Header 우선순위 오해를 피하는 방법을 이해하세요.","tags":["FAQ","인증","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"ko/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function i(s,e,l,c,h,n){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="_401-인증-실패-먼저-auth-mode-확인-다음-header-확인" tabindex="-1">401/인증 실패: 먼저 auth_mode 확인, 다음 Header 확인 <a class="header-anchor" href="#_401-인증-실패-먼저-auth-mode-확인-다음-header-확인" aria-label="Permalink to &quot;401/인증 실패: 먼저 auth_mode 확인, 다음 Header 확인&quot;">​</a></h1><h2 id="이-과정을-통해-할-수-있는-것" tabindex="-1">이 과정을 통해 할 수 있는 것 <a class="header-anchor" href="#이-과정을-통해-할-수-있는-것" aria-label="Permalink to &quot;이 과정을 통해 할 수 있는 것&quot;">​</a></h2><ul><li>3분 내에 401이 Antigravity Tools 인증 미들웨어에 의해 차단되었는지 판단</li><li><code>proxy.auth_mode</code> 네 가지 모드(특히 <code>auto</code>)가 현재 구성에서 어떻게 &quot;실제 유효값&quot;으로 작동하는지 명확히 이해</li><li>올바른 API Key Header(및 Header 우선순위 함정 피하기)로 요청을 통과시키는 방법</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p>클라이언트가 로컬 리버스 프록시를 호출할 때 <code>401 Unauthorized</code> 오류가 발생합니다:</p><ul><li>Python/OpenAI SDK: <code>AuthenticationError</code> 발생</li><li>curl: <code>HTTP/1.1 401 Unauthorized</code> 반환</li><li>HTTP 클라이언트: 응답 상태 코드 401</li></ul><h2 id="_401-인증-실패란" tabindex="-1">401/인증 실패란? <a class="header-anchor" href="#_401-인증-실패란" aria-label="Permalink to &quot;401/인증 실패란?&quot;">​</a></h2><p><strong>401 Unauthorized</strong>는 Antigravity Tools에서 가장 일반적인 의미는: 프록시가 인증을 활성화했고(<code>proxy.auth_mode</code> 결정), 하지만 요청이 올바른 API Key를 가지고 있지 않거나, 우선순위가 더 높은 불일치 Header를 가지고 있어 <code>auth_middleware()</code>가 즉시 401을 반환합니다.</p><div class="info custom-block"><p class="custom-block-title">먼저 &quot;프록시가 차단 중인지&quot; 확인</p><p>상류 플랫폼도 401을 반환할 수 있지만, 이 FAQ는 &quot;프록시 인증으로 인한 401&quot;만 처리합니다. 아래의 <code>/healthz</code>를 사용하여 빠르게 구분할 수 있습니다.</p></div><h2 id="빠른-문제-해결-이-순서대로-하세요" tabindex="-1">빠른 문제 해결(이 순서대로 하세요) <a class="header-anchor" href="#빠른-문제-해결-이-순서대로-하세요" aria-label="Permalink to &quot;빠른 문제 해결(이 순서대로 하세요)&quot;">​</a></h2><h3 id="_1단계-healthz로-인증이-차단-중인지-확인" tabindex="-1">1단계: <code>/healthz</code>로 &quot;인증이 차단 중인지&quot; 확인 <a class="header-anchor" href="#_1단계-healthz로-인증이-차단-중인지-확인" aria-label="Permalink to &quot;1단계: `/healthz`로 &quot;인증이 차단 중인지&quot; 확인&quot;">​</a></h3><p><strong>이유</strong><code>all_except_health</code>는 <code>/healthz</code>를 통과하지만 다른 라우팅을 차단합니다. 이를 통해 401이 프록시 인증 계층에서 오는지 빠르게 찾을 수 있습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 인증 Header 없이</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>예상 결과</strong></p><ul><li><code>auth_mode=all_except_health</code>(또는 <code>auto</code>이고 <code>allow_lan_access=true</code>)일 때: 보통 <code>200</code> 반환</li><li><code>auth_mode=strict</code>일 때: <code>401</code> 반환</li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code>는 라우팅 계층에서 GET</p><p>프록시는 라우팅에 <code>GET /healthz</code>를 등록합니다(참조: <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="_2단계-auth-mode의-실제-유효값-확인-특히-auto" tabindex="-1">2단계: <code>auth_mode</code>의 &quot;실제 유효값&quot; 확인(특히 <code>auto</code>) <a class="header-anchor" href="#_2단계-auth-mode의-실제-유효값-확인-특히-auto" aria-label="Permalink to &quot;2단계: `auth_mode`의 &quot;실제 유효값&quot; 확인(특히 `auto`)&quot;">​</a></h3><p><strong>이유</strong><code>auto</code>는 &quot;독립 정책&quot;이 아니며, <code>allow_lan_access</code>에 따라 실제 실행할 모드를 계산합니다.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>추가 조건</th><th>실제 유효값(effective mode)</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>GUI의 API Proxy 페이지에서 확인할 수 있습니다</strong>: <code>Allow LAN Access</code>와 <code>Auth Mode</code>.</p><hr><h3 id="_3단계-api-key가-비어-있지-않은지-동일한-값을-사용하고-있는지-확인" tabindex="-1">3단계: <code>api_key</code>가 비어 있지 않은지, 동일한 값을 사용하고 있는지 확인 <a class="header-anchor" href="#_3단계-api-key가-비어-있지-않은지-동일한-값을-사용하고-있는지-확인" aria-label="Permalink to &quot;3단계: `api_key`가 비어 있지 않은지, 동일한 값을 사용하고 있는지 확인&quot;">​</a></h3><p><strong>이유</strong> 인증이 활성화되어 있을 때 <code>proxy.api_key</code>가 비어 있으면 <code>auth_middleware()</code>는 모든 요청을 즉시 거부하고 오류 로그를 기록합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>예상 결과</strong></p><ul><li>API Proxy 페이지에서 <code>sk-</code>로 시작하는 키를 볼 수 있음(기본값은 <code>ProxyConfig::default()</code>에서 자동 생성됨)</li><li>&quot;Regenerate/편집&quot;을 클릭하여 저장하면 외부 요청은 즉시 새 키로 검증됨(재시작 불필요)</li></ul><hr><h3 id="_4단계-가장-간단한-header로-시도-복잡한-sdk는-먼저-사용하지-마세요" tabindex="-1">4단계: 가장 간단한 Header로 시도(복잡한 SDK는 먼저 사용하지 마세요) <a class="header-anchor" href="#_4단계-가장-간단한-header로-시도-복잡한-sdk는-먼저-사용하지-마세요" aria-label="Permalink to &quot;4단계: 가장 간단한 Header로 시도(복잡한 SDK는 먼저 사용하지 마세요)&quot;">​</a></h3><p><strong>이유</strong> 미들웨어는 <code>Authorization</code>을 우선 읽고, 다음 <code>x-api-key</code>, 마지막 <code>x-goog-api-key</code>를 읽습니다. 동시에 여러 Header를 보내면 앞에 있는 것이 틀리면 뒤에 있는 것이 맞아도 사용되지 않습니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 권장 작성법: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>예상 결과</strong>: <code>HTTP/1.1 200 OK</code>(또는 최소한 더 이상 401이 아님)</p><div class="info custom-block"><p class="custom-block-title">프록시의 Authorization 호환 세부 정보</p><p><code>auth_middleware()</code>는 <code>Authorization</code>의 값을 <code>Bearer </code> 접두사로 한 번 제거합니다. <code>Bearer </code> 접두사가 없으면 전체 값을 key로 비교합니다. 문서는 여전히 <code>Authorization: Bearer &lt;key&gt;</code>를 권장합니다(일반적인 SDK 규약에 더 가깝습니다).</p></div><p><strong>반드시 <code>x-api-key</code>를 사용해야 한다면</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="일반적인-문제-모두-소스-코드에서-실제-발생함" tabindex="-1">일반적인 문제(모두 소스 코드에서 실제 발생함) <a class="header-anchor" href="#일반적인-문제-모두-소스-코드에서-실제-발생함" aria-label="Permalink to &quot;일반적인 문제(모두 소스 코드에서 실제 발생함)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>현상</th><th>실제 원인</th><th>해결 방법</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>이지만 로컬 호출이 여전히 401</td><td><code>allow_lan_access=true</code>로 인해 <code>auto</code>가 <code>all_except_health</code>로 유효함</td><td><code>allow_lan_access</code>를 끄거나 클라이언트에 key를 추가하세요</td></tr><tr><td>&quot;명백히 x-api-key를 가지고 있는데&quot; 여전히 401</td><td>동시에 불일치하는 <code>Authorization</code>을 가지고 있어 미들웨어가 우선 사용함</td><td>불필요한 Header를 삭제하고 확인한 올바른 하나만 유지하세요</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code>가 여전히 401</td><td><code>Bearer</code> 뒤에 공백이 없어 <code>Bearer </code> 접두사 제거 불가</td><td><code>Authorization: Bearer &lt;key&gt;</code>로 변경</td></tr><tr><td>모든 요청이 401이고 로그에 <code>api_key is empty</code> 표시</td><td><code>proxy.api_key</code>가 비어 있음</td><td>GUI에서 다시 생성/설정하여 비어 있지 않은 key를 만드세요</td></tr></tbody></table><h2 id="이-과정-요약" tabindex="-1">이 과정 요약 <a class="header-anchor" href="#이-과정-요약" aria-label="Permalink to &quot;이 과정 요약&quot;">​</a></h2><ul><li>먼저 <code>/healthz</code>로 401이 프록시 인증 계층에서 오는지 찾아내기</li><li>다음 <code>auth_mode</code> 확인(특히 <code>auto</code>의 effective mode)</li><li>마지막으로 확인한 올바른 Header 하나만 가지고 검증(Header 우선순위 함정 피하기)</li></ul><h2 id="다음-과정-예고" tabindex="-1">다음 과정 예고 <a class="header-anchor" href="#다음-과정-예고" aria-label="Permalink to &quot;다음 과정 예고&quot;">​</a></h2><blockquote><p>다음 과정에서는 **<a href="./../429-rotation/">429/용량 오류: 계정 로테이션의 올바른 예상과 모델 용량 고갈의 오해</a>**를 학습합니다.</p><p>배울 내용:</p><ul><li>429가 &quot;할당량 부족&quot;인지 &quot;상류 속도 제한&quot;인지</li><li>계정 로테이션의 올바른 예상(언제 자동으로 전환되고 언제 안 되는지)</li><li>구성으로 429 확률을 낮추는 방법</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 펼치기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>ProxyAuthMode 열거형</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key 및 기본값</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>auto 모드 구문 분석(effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>인증 미들웨어(Header 추출 및 우선순위, /healthz 제외, OPTIONS 통과)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>/healthz 라우팅 등록 및 미들웨어 순서</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>인증 문서(모드 및 클라이언트 규약)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>핵심 열거형</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: 인증 모드</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: <code>auto</code>를 실제 정책으로 구문 분석</li><li><code>auth_middleware()</code>: 인증 실행(Header 추출 순서 및 /healthz 제외 포함)</li></ul></details>',45)])])}const k=t(r,[["render",i]]);export{p as __pageData,k as default};
